19	/// Репозиторий работы с Активностью (спектр Accum)
20	protocol ActivityDataRepository: SpectrumSettingsSetup {
21	    
22	    /// Издатель подключенного спектра
23	    var spectrumSubject: PassthroughSubject<SpectrumData, Never> { get }
24	    
25	    /// Запускает получение спектра
26	    func startSpectrumCollect()
27	    
28	    /// Останавливает получение спектра
29	    func cancelSpectrumCollect()
30	}
31	
32	final class ActivityDataRepositoryImpl: ActivityDataRepository {
33	    
34	    enum Consts {
35	        static let firstDelay: Double = 2.0
36	        static let defaultDelay: Double = 4.0
37	    }
38	    
39	    @Injected(\.deviceManager) private var deviceManager
40	    
41	    var specFormatVersion = false
42	    var spectrumDisabled = false
43	    
44	    private var spectrumCollectTask: Task<Void, Error>?
45	
46	    var spectrumSubject: PassthroughSubject<SpectrumData, Never> = .init()
47	    
48	    private var cancellable: Set<AnyCancellable> = .init()
49	
50	    func startSpectrumCollect() {
51	        guard !spectrumDisabled else { return }
52	        guard spectrumCollectTask == nil else { return }
53	        spectrumCollectTask = Task {
54	            var delay = Consts.firstDelay
55	            repeat {
56	                try await sendSpectrumCommand()
57	                try await Task.sleep(seconds: delay)
58	                delay = Consts.defaultDelay
59	            } while !Task.isCancelled
60	        }
61	    }
62	    
63	    func cancelSpectrumCollect() {
64	        spectrumCollectTask?.cancel()
65	        spectrumCollectTask = nil
66	    }
67	    
68	    private func sendSpectrumCommand() async throws {
69	        let result = await deviceManager.send(command: SpectrumAccumCommand(specFormatVersion: specFormatVersion))
70	        if case .success(let response) = result {
71	            let spectrum = SpectrumData(
72	                time: response.time,
73	                coefficients: response.coefficients,
74	                countNeg: response.countNeg,
75	                pulses: response.pulses
76	            )
77	            spectrumSubject.send(spectrum)
78	        }
79	    }
80	}
